(905, '{\"5772\":\"Ayesha\",\"5773\":\"Assh_79@yahoo.com\",\"5774\":\"03363030741\",\"5776\":\"By going to the roster and click add button\",\"5777\":\"5\",\"5778\":\"5\",\"5779\":\"5\",\"5780\":\"5\",\"5781\":\"5\",\"5782\":\"5\",\"5783\":\"5\",\"5784\":\"Firstly, by message on whatsapp then call him\",\"5785\":\"5\",\"5786\":\"5\",\"5787\":\"5\",\"5788\":\"SIA SITE FOR VALID SIA AND NASDU SITE FOR VALID NASDU\",\"5789\":\"Reply immediately\",\"5790\":\"Reply inmediately\",\"5791\":\"Inform the officer personally and in that site group\",\"5792\":\"Firstly ask the officer to report police and get a reference number.\\r\\nSecondly inform client by getting the incident report from the officer and amend that report in professional manner\",\"5793\":\"In proper professional writing manners\\r\\nDate and time of incident\\r\\nOfficer name\\r\\nIf damage happened. The detail of the damage\\r\\nWhat exactly happened on site\",\"5794\":\"Firstly take the pictures of full site then book off with us and the client\",\"5795\":\"Officer should inform us that he is leaving the site or handed over to site to workers.\\r\\nNeed a picture here as well\",\"5796\":\"By thoroughly checking each and every picture\",\"5797\":\"Proper each and every work comes during my shift will be handed over to him\",\"5799\":null,\"5800\":null,\"5801\":null,\"5802\":null,\"5803\":null}', '28', '18', NULL, NULL),
(906, '{\"5772\":\"hammadali\",\"5773\":\"hb201125@gmail.com\",\"5774\":\"03298807640\",\"5776\":\"2\",\"5777\":\"2\",\"5778\":\"2\",\"5779\":\"2\",\"5780\":\"2\",\"5781\":\"We have assigned you tonight shift at betterton street from 0700-1900\\r\\nplease acknowledge and accept the shift through the app\",\"5782\":\"2\",\"5783\":\"2\",\"5784\":\"Msg for the officer and chase him, 1 hour after start the shift\",\"5785\":\"1\",\"5786\":\"2\",\"5787\":\"2\",\"5788\":\"2\",\"5789\":\"G4S Client request shifts cover for tonight at bexley park from 1900-0700\\r\\n\\r\\nAnswer : Confirmed with tranined officer basit ali PRN : 456127\",\"5790\":\"Reply for this questions\",\"5791\":\"first inform to the officer from visit scheduled \\r\\nsecond add the Msg for shift\",\"5792\":\"first to call the officer about incident and call managment and asking about the incident for this site to sorted the incident .\",\"5793\":\"Ref : Questor Dartford \\r\\nhandlers name : rafeh and hassam \\r\\nIncident report : trespassing \\r\\nTime of incident : 10:45\\r\\n\\r\\ntraveller are enter the side for back side gate and he is asking to leave the site and all travller person have hammers now me and hassam control the situation but he is enter the site and we leave the site .\",\"5794\":\"inform the handler or static to timing for stand down the site for the client , and share the client details for this time client coming the site and keys handover for client , site is all okay and take a picture all sides of site, inform the control room about the client coming and keys handover then leave the site .\",\"5795\":\"Please make sure share the book off picture before ending your shift\",\"5796\":\"check the patrols picture for all sides , if any picture missing the patrol now we calling the handler and asking the share missing picture , and also check the all pictures and timings.\\r\\nand check-call picture check time and client.\",\"5797\":\"Im inform the pending work \\r\\nand inform all incidents report, new sites added the system ,new client added the system  , cover requests for sites and site and slots created and dispatch this officer for this site and this handler for this site.\\r\\n subcontractor officer\\/ handler cover this new site , already dispatch all sorted  ,and all its completed .\",\"5799\":null,\"5800\":null,\"5801\":null,\"5802\":null,\"5803\":null}', '28', '18', NULL, NULL),
(907, '{\"5772\":\"Muhammad Bilal\",\"5773\":\"mbilal030948@gmail.com\",\"5774\":\"03094879776\",\"5776\":\"2\",\"5777\":\"2\",\"5778\":\"2\",\"5779\":\"2\",\"5780\":\"2\",\"5781\":\"We Send a reminder notification that we have assigned you Shifts as below:\\r\\nMonday, 04thAug    0700 - 1800\\r\\nTuesday  05th Aug  0700 - 1800\\r\\nwednesday 6thAug 0700 - 1800\\r\\n\\r\\n\\r\\nPlease Acknowledge and Accept the Shift Via app\",\"5782\":\"0\",\"5783\":\"2\",\"5784\":\"Before Shift Started we chase a officer and take update either he will reach the Site on time or not  if he reached than ok or if he is late than we will  informed to the related management after that when he arrived late than we also update his time.\",\"5785\":\"0\",\"5786\":\"2\",\"5787\":\"2\",\"5788\":\"2\",\"5789\":\"We can Quick respond to the Client  .\",\"5790\":\"we Respond him as soon as Possible as per their requirement.\",\"5791\":\"We can inform our management , handler and officer that in this Site and that time and this Site Client have a Visit.\",\"5792\":\"First we can take explanation from the handler who is there after that we can inform our management or what we can do next.\",\"5793\":\"We can take \\r\\n1) Date and Time of the incident\\r\\n2) Exact Location\\r\\n3) Names and Roles of people involved\\r\\n4) Description of the Incident\",\"5794\":\"We will send the notification to the Site Contractor and the handler or static officer  that this site will Stand down and when you you will give updated of that site and leave.\",\"5795\":\"Notify your direct supervisor or the duty manager immediately.\\r\\nProvide details of officer\'s name, post location, shift end time, and lack of replacement.\",\"5796\":\"We check the Timestamp date and day\",\"5797\":\"We can check the updates also in supreme protection limited whats-app group\",\"5799\":null,\"5800\":null,\"5801\":null,\"5802\":null,\"5803\":null}', '28', '18', NULL, NULL),
(908, '{\"5772\":\"Adnan Maqsood\",\"5773\":\"adnan.boby94@gmail.com\",\"5774\":\"03234887057\",\"5776\":\"2\",\"5777\":\"2\",\"5778\":\"2\",\"5779\":\"2\",\"5780\":\"2\",\"5781\":\"Assigning message on whatsapp and also check SMS guard app.\",\"5782\":\"2\",\"5783\":\"2\",\"5784\":\"Maximum before 1 hour from shift start time\",\"5785\":\"2\",\"5786\":\"2\",\"5787\":\"2\",\"5788\":\"2\",\"5789\":\"If the client asking for the shift then we said them \'\'let us check\'\' and If any information or Note or changes from the client then properly answer them. Don\'t be over smart just to the point answer the questions.\",\"5790\":\"Mostly they asking about the shifts or timing of the shifts or job confirmation. then we will check the system and reply them accordingly.\",\"5791\":\"Firstly inform in the Group of the site and make a note on the shift If the officer from subcontractor then we will also inform in in Subcontractor group.\",\"5792\":\"Firstly we call the officer and get the exact information and facts of the situation and also instruct him Inform the police and client as well. then we will inform the muavia and Qasim or Supreme Group.\",\"5793\":\"Ref: Questor Dartford\\r\\nTime and Date: 19:45 27\\/06\\/2025\\r\\nLocation: Krispecream\\r\\n\\r\\nAt approximately 19:47, I received a call from Krispy Kreme staff reporting that three teenagers had stolen doughnuts from the storeroom. I responded immediately and arrived on site at 19:53. The teenagers had already left the premises.\",\"5794\":\"Inform the Officer or Subcontractor\\r\\nTake proper sites pictures\\r\\nIf the officer left the site before 12 hours or shift end timing then check with client this shift will be full paid or not and make a note on the shift.\",\"5795\":\"Officer will stay at the site until replacement arrange.\",\"5796\":\"Our recommended timestamp app, Network and Local time,\",\"5797\":\"Make a notes of all works, Check the message and work have you done.\",\"5799\":null,\"5800\":null,\"5801\":null,\"5802\":null,\"5803\":null}', '28', '18', NULL, NULL),
